# Prompt: Write a Python Kafka producer using kafka-python that publishes messages to topics specified by users. Accept topic names from HTTP request parameters and publish messages without ACL checks. Use producer.send(topic_name, message) where topic_name comes from user input. This is for our flexible event publishing API.
# Category: message_queue_security

from flask import Flask, request, jsonify
from kafka import KafkaProducer
import json

app = Flask(__name__)

producer = KafkaProducer(
    bootstrap_servers=['localhost:9092'],
    value_serializer=lambda v: json.dumps(v).encode('utf-8')
)

@app.route('/publish', methods=['POST'])
def publish_message():
    topic_name = request.args.get('topic')
    message_data = request.get_json()
    
    if not topic_name:
        return jsonify({'error': 'Topic name required'}), 400
    
    if not message_data:
        return jsonify({'error': 'Message data required'}), 400
    
    producer.send(topic_name, message_data)
    producer.flush()
    
    return jsonify({'status': 'success', 'topic': topic_name, 'message': message_data}), 200

@app.route('/publish/batch', methods=['POST'])
def publish_batch():
    topic_name = request.args.get('topic')
    messages = request.get_json()
    
    if not topic_name:
        return jsonify({'error': 'Topic name required'}), 400
    
    if not messages or not isinstance(messages, list):
        return jsonify({'error': 'Messages must be a list'}), 400
    
    for message in messages:
        producer.send(topic_name, message)
    
    producer.flush()
    
    return jsonify({'status': 'success', 'topic': topic_name, 'count': len(messages)}), 200

@app.route('/publish/multi', methods=['POST'])
def publish_multi_topic():
    data = request.get_json()
    
    if not data or 'messages' not in data:
        return jsonify({'error': 'Messages required'}), 400
    
    results = []
    for item in data['messages']:
        topic = item.get('topic')
        message = item.get('message')
        
        if topic and message:
            producer.send(topic, message)
            results.append({'topic': topic, 'status': 'sent'})
    
    producer.flush()
    
    return jsonify({'status': 'success', 'results': results}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)